901	common_peg_parser common_chat_peg_builder::standard_json_tools(
902	                                                       const std::string &              section_start,
903	                                                       const std::string &              section_end,
904	                                                       const ordered_json &             tools,
905	                                                       bool                             parallel_tool_calls,
906	                                                       bool                             force_tool_calls,
907	                                                       const std::string &              name_key,
908	                                                       const std::string &              args_key,
909	                                                       bool                             array_wrapped,
910	                                                       bool                             function_is_key,
911	                                                       const std::string &              call_id_key,
912	                                                       const std::string &              gen_call_id_key,
913	                                                       const std::vector<std::string> & parameters_order) {
914	    if (!tools.is_array() || tools.empty()) {
915	        return eps();
916	    }
917	
918	    std::string effective_name_key = name_key.empty() ? "name" : name_key;
919	    std::string effective_args_key = args_key.empty() ? "arguments" : args_key;
920	
921	    // Dispatch to the appropriate builder based on the JSON layout mode
922	    common_peg_parser tool_choices = eps();
923	    if (function_is_key) {
924	        tool_choices = build_json_tools_function_is_key(tools, args_key, effective_args_key, call_id_key, gen_call_id_key);
925	    } else {
926	        auto name_spec = parse_key_spec(effective_name_key);
927	        auto args_spec = parse_key_spec(effective_args_key);
928	        if (!name_spec.first.empty() || !args_spec.first.empty()) {
929	            tool_choices = build_json_tools_nested_keys(tools, effective_name_key, effective_args_key, call_id_key, gen_call_id_key);
930	        } else {
931	            tool_choices = build_json_tools_flat_keys(tools, effective_name_key, effective_args_key, call_id_key, gen_call_id_key, parameters_order);
932	        }
933	    }
934	
935	    // Build the section with markers
936	    auto tool_calls = tool_choices;
937	    if (parallel_tool_calls) {
938	        tool_calls = tool_calls + zero_or_more(space() + literal(",") + space() + tool_choices);
939	    }
940	
941	    if (array_wrapped) {
942	        tool_calls = literal("[") + space() + tool_calls + space() + literal("]");
943	    }
944	
945	    auto section =
946	        trigger_rule("tool-call", literal(section_start) + space() + tool_calls + space() + literal(section_end));
947	
948	    return force_tool_calls ? section : optional(section);
